import { expect, spyOn, test } from 'bun:test'
import type { ModelMessage, UserModelMessage } from 'ai'
import { z } from 'zod'
import type { FullToolInfo, ToolResponse } from '../'
import { type AgentToolRegistry, agentWorkflow } from './agent.workflow'
import { type JsonResponseMessage, toJsonModelMessage } from './json-ai-types'
import { type TaskEvent, type TaskEventEndTask, TaskEventKind } from './types'
import { createContext, type WorkflowTools } from './workflow'

function endTaskEvents(events: TaskEvent[]): TaskEventEndTask[] {
  return events.filter((event): event is TaskEventEndTask => event.kind === TaskEventKind.EndTask)
}

const createMockTool = (name: string, description: string, handler: (args: any) => Promise<ToolResponse>): FullToolInfo => ({
  name,
  description,
  parameters: z.object({
    path: z.string().describe('The path to list files from'),
  }),
  handler: (_: any, args: any) => handler(args),
})

const listFilesTool = createMockTool('listFiles', 'List files in a directory', async ({ path }: { path: string }) => {
  if (path === './src') {
    return {
      success: true,
      message: {
        type: 'text',
        value: JSON.stringify(['index.ts', 'agent.workflow.ts']),
      },
    }
  }
  return {
    success: true,
    message: { type: 'text', value: JSON.stringify([]) },
  }
})

test('should run agent workflow with a tool call and reply', async () => {
  const mockResponses: ModelMessage[] = [
    {
      role: 'assistant',
      content: [
        {
          type: 'tool-call',
          toolCallId: 'tool-call-1',
          toolName: 'listFiles',
          input: { path: './src' },
        },
      ],
    },
    {
      role: 'assistant',
      content: 'The files are index.ts and agent.workflow.ts',
    },
  ]

  const initialMessages: UserModelMessage[] = [{ role: 'user', content: 'What are the files in the src directory?' }]

  const allTools = [listFilesTool]
  const spied = { fn: (_: any) => {} }
  const taskEventSpy = spyOn(spied, 'fn')

  const tools: WorkflowTools<AgentToolRegistry> = {
    generateText: async () => {
      const response = mockResponses.shift()
      return [response!] as JsonResponseMessage[]
    },
    invokeTool: async (input) => {
      const { toolName, input: toolInput } = input
      const toolInfo = allTools.find((t) => t.name === toolName)
      if (!toolInfo) throw new Error(`Tool not found: ${toolName}`)
      // Type assertion needed for test mock - real tool handlers validate their own inputs
      return toolInfo.handler({} as any, toolInput as any)
    },
    taskEvent: async (input) => {
      taskEventSpy(input)
    },
  }

  const result = await agentWorkflow(
    {
      userMessage: initialMessages.map(toJsonModelMessage) as any,
      tools: allTools,
      systemPrompt: 'You are a helpful assistant.',
    },
    createContext(tools),
  )

  expect(result).toMatchObject({
    type: 'Exit',
    message: 'The files are index.ts and agent.workflow.ts',
  })
})

test('should pass system prompts separately from ordinary model messages', async () => {
  let capturedInput: AgentToolRegistry['generateText']['input'] | undefined

  const tools: WorkflowTools<AgentToolRegistry> = {
    generateText: async (input) => {
      capturedInput = structuredClone(input) as AgentToolRegistry['generateText']['input']
      return [{ role: 'assistant', content: 'Done.' }]
    },
    invokeTool: async () => {
      throw new Error('No tools should be invoked')
    },
    taskEvent: async () => {},
  }

  const result = await agentWorkflow(
    {
      userMessage: [toJsonModelMessage({ role: 'user', content: 'Do the thing.' })] as any,
      tools: [],
      systemPrompt: 'Use the dedicated system channel.',
    },
    createContext(tools),
  )

  if (!capturedInput) {
    throw new Error('generateText was not called')
  }

  expect(capturedInput.systemPrompt).toBe('Use the dedicated system channel.')
  expect(capturedInput.messages.some((message) => message.role === 'system')).toBe(false)
  expect(capturedInput.messages).toEqual([{ role: 'user', content: 'Do the thing.' }])
  expect(result.messages[0]).toEqual({ role: 'system', content: 'Use the dedicated system channel.' })
})

