test('should handle mixed valid and invalid tool calls by returning results for both', async () => {
  const mockResponses: ModelMessage[] = [
    {
      role: 'assistant',
      content: [
        {
          type: 'tool-call',
          toolCallId: 'call-1',
          toolName: 'listFiles',
          input: { path: './src' },
        },
        {
          type: 'tool-call',
          toolCallId: 'call-2',
          toolName: 'invalidTool',
          input: { some: 'param' },
        },
      ],
    },
    {
      role: 'assistant',
      content: 'Result received.',
    },
  ]

  const allTools = [listFilesTool]

  // We need to capture the tool results sent back to the model
  let capturedToolResults: any[] = []

  const tools: WorkflowTools<AgentToolRegistry> = {
    generateText: async ({ messages }) => {
      // Check if the last message is a tool result message and capture it
      const lastMsg = messages[messages.length - 1]
      if (lastMsg.role === 'tool') {
        capturedToolResults = lastMsg.content as any[]
      }

      const response = mockResponses.shift()
      if (!response) {
        // Return a dummy response to stop the loop if we run out of mocks
        return [{ role: 'assistant', content: 'Done' }] as JsonResponseMessage[]
      }
      return [response] as JsonResponseMessage[]
    },
    invokeTool: async (input) => {
      const { toolName, input: toolInput } = input
      const toolInfo = allTools.find((t) => t.name === toolName)
      if (!toolInfo) throw new Error(`Tool not found: ${toolName}`)
      // Type assertion needed for test mock - real tool handlers validate their own inputs
      return toolInfo.handler({} as any, toolInput as any)
    },
    taskEvent: async () => {},
  }

  await agentWorkflow(
    {
      userMessage: [toJsonModelMessage({ role: 'user', content: 'Do things.' })] as any,
      tools: allTools,
      systemPrompt: 'You are a helpful assistant.',
    },
    createContext(tools),
  )

  expect(capturedToolResults).toMatchSnapshot()
})

test('should continue after a recoverable error-text tool failure', async () => {
  const errorMessage = 'Error searching files: Ripgrep process exited with code 2: bad regex'
  const failingSearchFilesTool = createMockTool('searchFiles', 'Search files in a directory', async () => ({
    success: false,
    message: {
      type: 'error-text',
      value: errorMessage,
    },
  }))

  const mockResponses: ModelMessage[] = [
    {
      role: 'assistant',
      content: [
        {
          type: 'tool-call',
          toolCallId: 'search-call-1',
          toolName: 'searchFiles',
          input: { path: './src' },
        },
      ],
    },
    {
      role: 'assistant',
      content: 'The search failed because the regex is invalid.',
    },
  ]

  const events: any[] = []
  let capturedToolResults: any[] | undefined

  const tools: WorkflowTools<AgentToolRegistry> = {
    generateText: async ({ messages }) => {
      const lastMessage = messages[messages.length - 1]
      if (lastMessage.role === 'tool') {
        capturedToolResults = structuredClone(lastMessage.content as any[])
      }

      const response = mockResponses.shift()
      return [response!] as JsonResponseMessage[]
    },
    invokeTool: async ({ toolName, input }) => {
      if (toolName !== failingSearchFilesTool.name) {
        throw new Error(`Tool not found: ${toolName}`)
      }
      return await failingSearchFilesTool.handler({} as any, input as any)
    },
    taskEvent: async (input) => {
      events.push(input)
    },
  }

  const result = await agentWorkflow(
    {
      userMessage: [toJsonModelMessage({ role: 'user', content: 'Search for this regex.' })] as any,
      tools: [failingSearchFilesTool],
      systemPrompt: 'You are a helpful assistant.',
    },
    createContext(tools),
  )

  expect(result).toMatchObject({
    type: 'Exit',
    message: 'The search failed because the regex is invalid.',
  })
  expect(events).toContainEqual({
    kind: TaskEventKind.ToolError,
    tool: 'searchFiles',
    error: {
      type: 'error-text',
      value: errorMessage,
    },
  })
  expect(capturedToolResults).toEqual([
    {
      type: 'tool-result',
      toolCallId: 'search-call-1',
      toolName: 'searchFiles',
      output: {
        type: 'error-text',
        value: errorMessage,
      },
    },
  ])
})

